# Security: Sanitize log messages to prevent injection
class SecureLogFilter(logging.Filter):
    def filter(self, record):
        if hasattr(record, 'msg'):
            record.msg = str(record.msg).replace('\n', ' ').replace('\r', ' ')[:200]
        return True

