@dataclass
class Document:
    id: str
    content: str
    metadata: Dict
    embedding: Optional[List[float]] = None


class InputValidator:
    """Validates and sanitizes all user inputs"""
    
    # Allowlist for query characters
    ALLOWED_QUERY_PATTERN = re.compile(r'^[a-zA-Z0-9\s\.\,\?\!\-\_\(\)]+$')
    MAX_QUERY_LENGTH = 500
    MAX_DOCUMENT_SIZE = 10 * 1024 * 1024  # 10MB
    ALLOWED_FILE_EXTENSIONS = {'.txt', '.md', '.json', '.csv'}
    
    @staticmethod
    def validate_query(query: str) -> str:
        """Validate and sanitize user query"""
        if not isinstance(query, str):
            raise ValueError("Query must be a string")
        
        query = query.strip()
        
        if not query:
            raise ValueError("Query cannot be empty")
        
        if len(query) > InputValidator.MAX_QUERY_LENGTH:
            raise ValueError(f"Query exceeds maximum length of {InputValidator.MAX_QUERY_LENGTH}")
        
        # Sanitize: remove control characters
        query = ''.join(char for char in query if ord(char) >= 32 or char in '\n\t')
        
        # Validate against allowlist
        if not InputValidator.ALLOWED_QUERY_PATTERN.match(query):
            raise ValueError("Query contains invalid characters")
        
        return query
    
    @staticmethod
    def validate_file_path(file_path: str) -> Path:
        """Validate file path to prevent directory traversal"""
        if not isinstance(file_path, str):
            raise ValueError("File path must be a string")
        
        # Resolve to absolute path and check for traversal
        try:
            path = Path(file_path).resolve()
        except Exception as e:
            raise ValueError(f"Invalid file path: {e}")
        
        # Ensure file exists and is a file
        if not path.exists():
            raise ValueError("File does not exist")
        
        if not path.is_file():
            raise ValueError("Path is not a file")
        
        # Check file extension allowlist
        if path.suffix.lower() not in InputValidator.ALLOWED_FILE_EXTENSIONS:
            raise ValueError(f"File type not allowed. Allowed types: {InputValidator.ALLOWED_FILE_EXTENSIONS}")
        
        # Check file size
        if path.stat().st_size > InputValidator.MAX_DOCUMENT_SIZE:
            raise ValueError(f"File exceeds maximum size of {InputValidator.MAX_DOCUMENT_SIZE} bytes")
        
        return path
    
    @staticmethod
    def validate_top_k(top_k: int) -> int:
        """Validate top_k parameter"""
        if not isinstance(top_k, int):
            raise ValueError("top_k must be an integer")
        
        if top_k < 1 or top_k > 20:
            raise ValueError("top_k must be between 1 and 20")
        
        return top_k


class SecureVectorDatabase:
    """In-memory vector database with security controls"""
    
    def __init__(self):
        self.documents: Dict[str, Document] = {}
        self._access_log = []
    
    def add_document(self, doc: Document):
        """Add document with access logging"""
        if not isinstance(doc, Document):
            raise ValueError("Invalid document type")
        
        # Generate secure document ID
        doc_hash = hashlib.sha256(doc.content.encode('utf-8')).hexdigest()[:16]
        doc.id = doc_hash
        
        self.documents[doc.id] = doc
        self._log_access('add_document', doc.id)
        logger.info(f"Document added: {doc.id}")
    
    def search(self, query_embedding: List[float], top_k: int = 5) -> List[Document]:
        """Search with rate limiting and access control"""
        top_k = InputValidator.validate_top_k(top_k)
        
        if not isinstance(query_embedding, list):
            raise ValueError("Query embedding must be a list")
        
        # Simple cosine similarity search
        results = []
        for doc in self.documents.values():
            if doc.embedding:
                similarity = self._cosine_similarity(query_embedding, doc.embedding)
                results.append((similarity, doc))
        
        results.sort(reverse=True, key=lambda x: x[0])
        top_results = [doc for _, doc in results[:top_k]]
        
        self._log_access('search', f"returned_{len(top_results)}_docs")
        return top_results
    
    def _cosine_similarity(self, vec1: List[float], vec2: List[float]) -> float:
        """Calculate cosine similarity"""
        if len(vec1) != len(vec2):
            return 0.0
        
        dot_product = sum(a * b for a, b in zip(vec1, vec2))
        magnitude1 = sum(a * a for a in vec1) ** 0.5
        magnitude2 = sum(b * b for b in vec2) ** 0.5
        
        if magnitude1 == 0 or magnitude2 == 0:
            return 0.0
        
        return dot_product / (magnitude1 * magnitude2)
    
    def _log_access(self, action: str, details: str):
        """Log access without sensitive data"""
        self._access_log.append({
            'timestamp': datetime.utcnow().isoformat(),
            'action': action,
            'details': details[:100]  # Limit log size
        })


