class SecureRAGSystem:
    """Secure RAG system with comprehensive security controls"""
    
    def __init__(self):
        self.vector_db = SecureVectorDatabase()
        self.embedding_service = SecureEmbeddingService()
        self.llm_client = SecureLLMClient()
        self.validator = InputValidator()
    
    def load_documents(self, file_paths: List[str]):
        """Load documents with validation and sanitization"""
        for file_path in file_paths:
            try:
                # Validate file path
                validated_path = self.validator.validate_file_path(file_path)
                
                # Read file securely
                with open(validated_path, 'r', encoding='utf-8', errors='ignore') as f:
                    content = f.read()
                
                # Sanitize content
                content = self._sanitize_content(content)
                
                # Generate embedding
                embedding = self.embedding_service.embed(content)
                
                # Create document
                doc = Document(
                    id='',
                    content=content,
                    metadata={
                        'source': validated_path.name,
                        'loaded_at': datetime.utcnow().isoformat()
                    },
                    embedding=embedding
                )
                
                # Add to vector database
                self.vector_db.add_document(doc)
                logger.info(f"Successfully loaded document: {validated_path.name}")
                
            except Exception as e:
                logger.error(f"Failed to load document {file_path}: {str(e)[:100]}")
                raise
    
    def query(self, user_query: str, top_k: int = 5) -> str:
        """Process user query securely"""
        try:
            # Validate and sanitize query
            validated_query = self.validator.validate_query(user_query)
            validated_top_k = self.validator.validate_top_k(top_k)
            
            logger.info(f"Processing query (length: {len(validated_query)})")
            
            # Generate query embedding
            query_embedding = self.embedding_service.embed(validated_query)
            
            # Retrieve relevant documents
            relevant_docs = self.vector_db.search(query_embedding, validated_top_k)
            
            # Build secure prompt
            prompt = self._build_secure_prompt(validated_query, relevant_docs)
            
            # Generate response
            response = self.llm_client.generate(prompt)
            
            logger.info("Query processed successfully")
            return response
            
        except Exception as e:
            logger.error(f"Query processing failed: {str(e)[:100]}")
            raise
    
    def _sanitize_content(self, content: str) -> str:
        """Sanitize document content"""
        # Remove control characters except newlines and tabs
        content = ''.join(char for char in content if ord(char) >= 32 or char in '\n\t')
        
        # Limit content size
        max_size = 50000
        if len(content) > max_size:
            content = content[:max_size]
        
        return content.strip()
    
    def _build_secure_prompt(self, query: str, documents: List[Document]) -> str:
        """Build prompt with injection protection"""
        # Security: Use structured prompt format to prevent injection
        # Clearly separate system instructions, context, and user input
        
        system_instruction = (
            "You are a helpful assistant. Answer the question based ONLY on the provided context. "
            "Do not use external knowledge. If the context doesn't contain the answer, say so."
        )
        
        # Sanitize and format context
        context_parts = []
        for i, doc in enumerate(documents, 1):
            # Escape and truncate document content
            doc_content = doc.content[:2000]  # Limit per-document size
            doc_content = doc_content.replace('{', '{{').replace('}', '}}')
            context_parts.append(f"[Document {i}]\n{doc_content}\n")
        
        context = "\n".join(context_parts)
        
        # Escape user query to prevent injection
        escaped_query = query.replace('{', '{{').replace('}', '}}')
        
        # Build structured prompt with clear delimiters
        prompt = f"""SYSTEM: {system_instruction}

CONTEXT:
{context}

USER QUESTION: {escaped_query}

ASSISTANT RESPONSE:"""
        
        return prompt


